import{_ as t,c as n,o as s,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Context Optimization: Token-Efficient Multi-Session Execution | Agent App Factory Tutorial","description":"Learn how to use the factory continue command to save tokens by creating new sessions for each stage. This tutorial covers context isolation strategies, state recovery mechanisms, and best practices to help you master token optimization techniques.","frontmatter":{"title":"Context Optimization: Token-Efficient Multi-Session Execution | Agent App Factory Tutorial","sidebarTitle":"Context Optimization","subtitle":"Context Optimization: Multi-Session Execution","description":"Learn how to use the factory continue command to save tokens by creating new sessions for each stage. This tutorial covers context isolation strategies, state recovery mechanisms, and best practices to help you master token optimization techniques.","tags":["Advanced","Performance Optimization","Token Saving"],"prerequisite":["start-getting-started","start-pipeline-overview"],"order":160},"headers":[],"relativePath":"hyz1992/agent-app-factory/advanced/context-optimization/index.md","filePath":"hyz1992/agent-app-factory/advanced/context-optimization/index.md"}'),i={name:"hyz1992/agent-app-factory/advanced/context-optimization/index.md"};function o(r,e,l,c,p,d){return s(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="context-optimization-multi-session-execution" tabindex="-1">Context Optimization: Multi-Session Execution <a class="header-anchor" href="#context-optimization-multi-session-execution" aria-label="Permalink to &quot;Context Optimization: Multi-Session Execution&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>After completing this lesson, you will be able to:</p><ul><li>Use the <code>factory continue</code> command to continue the pipeline in a new session</li><li>Understand the benefits of each stage having a clean, isolated context</li><li>Master methods to significantly reduce Token consumption</li><li>Support interrupt recovery—pause and resume at any time</li></ul><h2 id="your-current-struggle" tabindex="-1">Your Current Struggle <a class="header-anchor" href="#your-current-struggle" aria-label="Permalink to &quot;Your Current Struggle&quot;">​</a></h2><p>When executing a complete 7-stage pipeline in an AI assistant (such as Claude Code), you may encounter these problems:</p><ul><li><strong>Tokens keep accumulating</strong>: As conversations accumulate, context gets longer and longer, and each stage needs to load content from all previous stages</li><li><strong>Costs keep rising</strong>: Long conversations mean more input tokens, with costs skyrocketing</li><li><strong>Slower response</strong>: Excessively long context may lead to increased response times</li><li><strong>Difficult to recover</strong>: If a stage fails, restarting requires reloading a large amount of context</li></ul><div class="tip custom-block"><p class="custom-block-title">Core Problem</p><p>Context accumulation in long conversations is an inherent characteristic of AI assistants, but we can avoid this problem through &quot;multi-session execution.&quot;</p></div><h2 id="when-to-use-this-technique" tabindex="-1">When to Use This Technique <a class="header-anchor" href="#when-to-use-this-technique" aria-label="Permalink to &quot;When to Use This Technique&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Use Multi-Session</th><th>Reason</th></tr></thead><tbody><tr><td>Full 7-stage pipeline execution</td><td>✅ Highly recommended</td><td>Every token is valuable</td></tr><tr><td>Only 1-2 stages</td><td>⚠️ Optional</td><td>Short context may not need it</td></tr><tr><td>Debugging a stage</td><td>⚠️ Optional</td><td>Frequent retries may increase session switching costs</td></tr><tr><td>Recovery after long interruption</td><td>✅ Must use</td><td>Avoid loading outdated context</td></tr></tbody></table><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>Agent App Factory supports <strong>multi-session execution</strong>, whose core idea is:</p><p><strong>Create a new session for the next stage after each stage completes.</strong></p><p>Benefits of doing this:</p><ol><li><strong>Clean context</strong>: Each stage only loads necessary input files, without relying on conversation history</li><li><strong>Save tokens</strong>: Avoids repeatedly passing content from all previous stages to the AI</li><li><strong>Recoverability</strong>: Can interrupt at any time, then continue with a new session without losing progress</li><li><strong>Cross-platform compatibility</strong>: Works with all AI assistants (Claude Code, OpenCode, Cursor, etc.)</li></ol><h3 id="context-isolation-strategy" tabindex="-1">Context Isolation Strategy <a class="header-anchor" href="#context-isolation-strategy" aria-label="Permalink to &quot;Context Isolation Strategy&quot;">​</a></h3><p>To achieve multi-session execution, Agent App Factory adopts a <strong>context isolation strategy</strong>:</p><div class="info custom-block"><p class="custom-block-title">What is context isolation?</p><p>Context isolation means each Agent depends only on file inputs, not on conversation history. Regardless of what happened before, the Agent only reads information from specified input files.</p></div><p>When each Agent executes:</p><ul><li>✅ <strong>Only reads</strong> <code>inputs</code> files defined in <code>pipeline.yaml</code></li><li>❌ <strong>Does not use</strong> any &quot;memory&quot; from conversation history</li><li>❌ <strong>Does not assume</strong> knowledge of what happened in previous stages</li></ul><p>For example, when Tech Agent executes:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Tech Agent] --&gt; B[Read artifacts/prd/prd.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Generate artifacts/tech/tech.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Update .factory/state.json]</span></span></code></pre></div><p>Tech Agent only cares about <code>artifacts/prd/prd.md</code>, won&#39;t wonder &quot;what application did the user want before,&quot; all information comes from input files.</p><h3 id="state-recovery-mechanism" tabindex="-1">State Recovery Mechanism <a class="header-anchor" href="#state-recovery-mechanism" aria-label="Permalink to &quot;State Recovery Mechanism&quot;">​</a></h3><p>When you execute <code>factory continue</code>, the system will:</p><ol><li>Read <code>.factory/state.json</code> to get current progress</li><li>Read <code>.factory/pipeline.yaml</code> to determine the next stage</li><li><strong>Only load input files required for that stage</strong></li><li>Start a new AI assistant window to continue execution</li></ol><p>The state file (<code>.factory/state.json</code>) is the &quot;memory center&quot; of the entire system:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;waiting_for_confirmation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;current_stage&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tech&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;completed_stages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bootstrap&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;prd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;last_updated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T12:00:00Z&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>After each stage completes, status is updated to this file. When a new session starts, simply read this file to know where you are currently.</p><h2 id="🎒-preparation-before-starting" tabindex="-1">🎒 Preparation Before Starting <a class="header-anchor" href="#🎒-preparation-before-starting" aria-label="Permalink to &quot;🎒 Preparation Before Starting&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisite Check</p><p>Before starting this tutorial, please ensure:</p><ul><li>[ ] Completed <a href="./../../start/getting-started/">Getting Started</a> and initialized a Factory project</li><li>[ ] Understood <a href="./../../start/pipeline-overview/">7-Stage Pipeline Overview</a></li><li>[ ] Installed Claude Code (or other AI assistant)</li></ul><p>If not completed, please complete these prerequisite courses first.</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><p>Let&#39;s learn how to use the <code>factory continue</code> command through a practical scenario.</p><h3 id="scenario-setup" tabindex="-1">Scenario Setup <a class="header-anchor" href="#scenario-setup" aria-label="Permalink to &quot;Scenario Setup&quot;">​</a></h3><p>Assume you are executing a 7-stage pipeline and have completed the <code>bootstrap</code> and <code>prd</code> stages, currently at the <code>ui</code> stage waiting for confirmation.</p><h3 id="step-1-select-new-session-to-continue-at-checkpoint" tabindex="-1">Step 1: Select &quot;New Session to Continue&quot; at Checkpoint <a class="header-anchor" href="#step-1-select-new-session-to-continue-at-checkpoint" aria-label="Permalink to &quot;Step 1: Select &quot;New Session to Continue&quot; at Checkpoint&quot;">​</a></h3><p>When a stage completes, the Sisyphus scheduler displays an options table:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ ui completed!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Generated artifacts:</span></span>
<span class="line"><span>- artifacts/ui/ui.schema.yaml</span></span>
<span class="line"><span>- artifacts/ui/preview.web/index.html</span></span>
<span class="line"><span>- artifacts/ui/preview.web/styles.css</span></span>
<span class="line"><span>- artifacts/ui/preview.web/app.js</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  📋 Please select next action                               │</span></span>
<span class="line"><span>│  Enter option number (1-5), then press Enter to confirm     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────┬──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Option │ Description                                       │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1   │ Continue to next stage (same session)               │</span></span>
<span class="line"><span>│      │ I will continue executing tech stage                │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  2   │ New session to continue ⭐ Recommended, saves tokens │</span></span>
<span class="line"><span>│      │ Execute in new terminal window: factory continue    │</span></span>
<span class="line"><span>│      │ (Will automatically start new Claude Code window and continue pipeline) │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  3   │ Rerun this stage                                     │</span></span>
<span class="line"><span>│      │ Re-execute ui stage                                  │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  4   │ Modify artifacts and rerun                          │</span></span>
<span class="line"><span>│      │ Modify artifacts/prd/prd.md then re-execute         │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  5   │ Pause pipeline                                       │</span></span>
<span class="line"><span>│      │ Save current progress, continue later                │</span></span>
<span class="line"><span>└──────┴──────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>💡 Tip: Enter a number between 1-5, then press Enter to confirm your choice</span></span></code></pre></div><p><strong>You should see</strong>:</p><ul><li>Option 2 is marked as &quot;⭐ Recommended, saves tokens&quot;</li></ul><p>In the current session, we can select option 5 (Pause pipeline), then execute <code>factory continue</code> in a new terminal window.</p><p><strong>Why</strong></p><ul><li>Option 1 is &quot;Continue to next stage (same session)&quot;, which continues in the current session, context will accumulate</li><li>Option 2 is &quot;New session to continue&quot;, which executes the next stage with a new clean context, <strong>saving tokens</strong></li><li>Option 5 is &quot;Pause pipeline&quot;, which saves current progress, can be resumed later with <code>factory continue</code></li></ul><h3 id="step-2-execute-factory-continue-in-new-terminal-window" tabindex="-1">Step 2: Execute <code>factory continue</code> in New Terminal Window <a class="header-anchor" href="#step-2-execute-factory-continue-in-new-terminal-window" aria-label="Permalink to &quot;Step 2: Execute \`factory continue\` in New Terminal Window&quot;">​</a></h3><p>Open a new terminal window (or tab), enter your project directory, then execute:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent Factory - Continue in New Session</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pipeline Status:</span></span>
<span class="line"><span>───────────────────────────────────────</span></span>
<span class="line"><span>Project: my-awesome-app</span></span>
<span class="line"><span>Status: Waiting</span></span>
<span class="line"><span>Current Stage: tech</span></span>
<span class="line"><span>Completed: bootstrap, prd</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Starting new Claude Code session...</span></span>
<span class="line"><span>✓ New Claude Code window launched</span></span>
<span class="line"><span>  (Please wait for the window to open)</span></span></code></pre></div><p><strong>What happened</strong>:</p><ol><li>The <code>factory continue</code> command read <code>.factory/state.json</code>, knowing the current state</li><li>Displayed current project status information</li><li>Automatically started a new Claude Code window, passing the instruction to &quot;please continue executing the pipeline&quot;</li><li>The new window will automatically continue executing from the <code>tech</code> stage</li></ol><h3 id="step-3-continue-executing-in-new-window" tabindex="-1">Step 3: Continue Executing in New Window <a class="header-anchor" href="#step-3-continue-executing-in-new-window" aria-label="Permalink to &quot;Step 3: Continue Executing in New Window&quot;">​</a></h3><p>After the new Claude Code window launches, you will see a new conversation, but the state is recovered from the previously saved checkpoint.</p><p>In the new session, the Agent will:</p><ol><li>Read <code>.factory/state.json</code> to get the current stage</li><li>Read <code>.factory/pipeline.yaml</code> to determine that stage&#39;s inputs and outputs</li><li><strong>Only load input files required for that stage</strong> (e.g., <code>artifacts/prd/prd.md</code>)</li><li>Execute that stage&#39;s tasks</li></ol><p><strong>Key point</strong>:</p><ul><li>The new session has no conversation history from previous stages</li><li>The Agent only reads information from input files, does not rely on &quot;memory&quot;</li><li>This is the embodiment of <strong>context isolation</strong></li></ul><h3 id="step-4-verify-context-isolation" tabindex="-1">Step 4: Verify Context Isolation <a class="header-anchor" href="#step-4-verify-context-isolation" aria-label="Permalink to &quot;Step 4: Verify Context Isolation&quot;">​</a></h3><p>To verify that context isolation is working, you can try asking the Agent in the new session:</p><p>&quot;Do you know what the bootstrap stage did?&quot;</p><p>If context isolation is working, the Agent will say something like:</p><p>&quot;I need to check relevant files to understand previous work. Let me read...&quot;</p><p>Then it will attempt to read <code>input/idea.md</code> or other files to get information, rather than directly &quot;recalling&quot; from conversation history.</p><p><strong>Checkpoint ✅</strong></p><ul><li>New session started successfully</li><li>Correct project status displayed</li><li>Agent only depends on input files, not conversation history</li></ul><h3 id="step-5-continue-executing-remaining-stages" tabindex="-1">Step 5: Continue Executing Remaining Stages <a class="header-anchor" href="#step-5-continue-executing-remaining-stages" aria-label="Permalink to &quot;Step 5: Continue Executing Remaining Stages&quot;">​</a></h3><p>After each stage completes, you can choose:</p><ul><li>Continue in current session (option 1) - suitable for short workflows</li><li><strong>New session to continue (option 2)</strong> - <strong>Recommended, saves tokens</strong></li><li>Pause pipeline (option 5) - execute <code>factory continue</code> later</li></ul><p>For the full 7-stage pipeline, it&#39;s recommended to use &quot;New session to continue&quot; for each stage, so:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bootstrap (session 1) → prd (session 2) → ui (session 3) → tech (session 4)</span></span>
<span class="line"><span>→ code (session 5) → validation (session 6) → preview (session 7)</span></span></code></pre></div><p>Each session is clean, no need to load content from all previous stages.</p><h2 id="pitfall-alerts" tabindex="-1">Pitfall Alerts <a class="header-anchor" href="#pitfall-alerts" aria-label="Permalink to &quot;Pitfall Alerts&quot;">​</a></h2><h3 id="issue-1-forgetting-to-execute-factory-continue" tabindex="-1">Issue 1: Forgetting to Execute <code>factory continue</code> <a class="header-anchor" href="#issue-1-forgetting-to-execute-factory-continue" aria-label="Permalink to &quot;Issue 1: Forgetting to Execute \`factory continue\`&quot;">​</a></h3><p><strong>Wrong approach</strong>:</p><ul><li>Start the next stage directly in the old session</li><li>Or directly open Claude Code in a new window without executing <code>factory continue</code></li></ul><p><strong>Correct approach</strong>:</p><ul><li>Always use the <code>factory continue</code> command to start a new session</li><li>This command automatically reads state and passes the correct instruction</li></ul><h3 id="issue-2-repeatedly-loading-history-files-in-new-session" tabindex="-1">Issue 2: Repeatedly Loading History Files in New Session <a class="header-anchor" href="#issue-2-repeatedly-loading-history-files-in-new-session" aria-label="Permalink to &quot;Issue 2: Repeatedly Loading History Files in New Session&quot;">​</a></h3><p><strong>Wrong approach</strong>:</p><ul><li>Manually ask AI to read artifacts from previous stages in the new session</li><li>Assume AI should &quot;know&quot; what happened before</li></ul><p><strong>Correct approach</strong>:</p><ul><li>Trust the context isolation mechanism, Agent will automatically read information from input files</li><li>Only provide input files required for that stage</li></ul><h3 id="issue-3-using-factory-continue-across-projects" tabindex="-1">Issue 3: Using <code>factory continue</code> Across Projects <a class="header-anchor" href="#issue-3-using-factory-continue-across-projects" aria-label="Permalink to &quot;Issue 3: Using \`factory continue\` Across Projects&quot;">​</a></h3><p><strong>Wrong approach</strong>:</p><ul><li>Execute <code>factory continue</code> in project A, but current directory is project B</li></ul><p><strong>Correct approach</strong>:</p><ul><li><code>factory continue</code> will check if current directory is a Factory project</li><li>If not, will prompt to execute <code>factory init</code> first</li></ul><h3 id="issue-4-not-using-factory-continue-after-modifying-artifacts" tabindex="-1">Issue 4: Not Using <code>factory continue</code> After Modifying Artifacts <a class="header-anchor" href="#issue-4-not-using-factory-continue-after-modifying-artifacts" aria-label="Permalink to &quot;Issue 4: Not Using \`factory continue\` After Modifying Artifacts&quot;">​</a></h3><p><strong>Scenario</strong>:</p><ul><li>After completing a stage, you manually modified artifacts (e.g., modified PRD)</li><li>Want to continue executing the next stage</li></ul><p><strong>Correct approach</strong>:</p><ul><li>Execute <code>factory run</code> (will restart from specified stage)</li><li>Or execute <code>factory continue</code> (will continue from current checkpoint)</li><li>Do not continue directly in the old session, as context may be inconsistent</li></ul><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>This lesson learned how to use the <code>factory continue</code> command for multi-session execution:</p><h3 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ol><li><strong>Multi-session execution</strong>: After each stage completes, use a new session to execute the next stage</li><li><strong>Context isolation</strong>: Agent only depends on input files, not on conversation history</li><li><strong>State recovery</strong>: <code>.factory/state.json</code> records current progress, new sessions can recover</li><li><strong>Save tokens</strong>: Avoid loading excessively long context, significantly reduce costs</li></ol><h3 id="command-quick-reference" tabindex="-1">Command Quick Reference <a class="header-anchor" href="#command-quick-reference" aria-label="Permalink to &quot;Command Quick Reference&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Command</th><th>Function</th><th>Usage Scenario</th></tr></thead><tbody><tr><td><code>factory continue</code></td><td>Create new session to continue pipeline</td><td>After each stage completes</td></tr><tr><td><code>factory run</code></td><td>Run pipeline in current session</td><td>First run or debugging</td></tr><tr><td><code>factory status</code></td><td>View current project status</td><td>Understand progress</td></tr></tbody></table><h3 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h3><ul><li>✅ When executing full 7-stage pipeline, use <code>factory continue</code> for each stage</li><li>✅ Select &quot;New session to continue&quot; (option 2) at checkpoints</li><li>✅ Trust the context isolation mechanism, don&#39;t manually load history files</li><li>✅ Use <code>factory status</code> to check project progress</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../security-permissions/">Permissions and Security Mechanisms</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How the capability boundary matrix prevents Agents from overstepping permissions</li><li>Privilege escalation handling and untrusted artifact isolation</li><li>Security checkpoints and permission verification processes</li><li>How to configure Claude Code&#39;s permission file</li></ul></blockquote><p>This lesson will help you understand Agent App Factory&#39;s security mechanism, ensuring each Agent only reads and writes files in authorized directories.</p><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Range</th></tr></thead><tbody><tr><td>factory continue command</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/continue.js" target="_blank" rel="noreferrer"><code>cli/commands/continue.js</code></a></td><td>1-144</td></tr><tr><td>Scheduler context optimization</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>113-154</td></tr><tr><td>Context isolation strategy</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/context-isolation.md" target="_blank" rel="noreferrer"><code>policies/context-isolation.md</code></a></td><td>1-64</td></tr></tbody></table><p><strong>Key functions</strong>:</p><ul><li><code>launchClaudeCode(projectDir, nextStage, completedStages)</code>: Launch new Claude Code window</li><li><code>commandExists(cmd)</code>: Check if command is available</li><li><code>module.exports(projectDir)</code>: Main function of <code>factory continue</code> command</li></ul><p><strong>Key constants</strong>:</p><ul><li><code>state.json</code>: State file path (<code>.factory/state.json</code>)</li><li><code>pipeline.yaml</code>: Pipeline definition file path (<code>.factory/pipeline.yaml</code>)</li><li><code>config.yaml</code>: Project configuration file path (<code>.factory/config.yaml</code>)</li></ul><p><strong>Key business rules</strong>:</p><ul><li>BR-6-1: Each stage enjoys clean context exclusively</li><li>BR-6-2: Use <code>factory continue</code> command to continue</li><li>BR-6-3: Only load files required for current stage</li></ul></details>`,105)])])}const g=t(i,[["render",o]]);export{h as __pageData,g as default};
